const fs = require('fs'); const data = require('./company_profiling_data.json'); const companies = require('./companies_data.json').results; companies.forEach(c => c.profiling = data.profiles[c.id] || null); const opt = { label: 'Videokuvaaja', tags: ['videotuotanto', 'videokuvaus', 'videokuvaaja'], profilointi_filter: { section: 'events_and_celebrations', field: 'refinement_tags', value: 'h‰‰video' } }; const taxonomyData = null; const currentProfilingKey = 'events_and_celebrations'; const matches = companies.filter(c => { let isProfiledMatch = false; const checkFuzzyMatch = (target, query) => { if (!target || !query) return false; const t = String(target).toLowerCase(); const q = String(query).toLowerCase(); return t === q || t.includes(q) || q.includes(t) || t === q + 't' || q === t + 't'; }; if (opt.profilointi_filter) { const pf = opt.profilointi_filter; const catData = c.profiling && c.profiling[pf.section]; if (catData) { const actualVal = catData[pf.field]; if (Array.isArray(actualVal)) { if (actualVal.some(v => checkFuzzyMatch(v, pf.value))) isProfiledMatch = true; } } } if (!isProfiledMatch && opt.tags) { const isPhotoSearch = opt.tags.some(t => t.includes('valokuva')); const isVideoSearch = opt.tags.some(t => t.includes('video') || t === 'videotuotanto'); const coreNodeLinks = c.profiling?.core?.node_links || []; if ((isPhotoSearch && coreNodeLinks.includes('VALOKUVAUS')) || (isVideoSearch && coreNodeLinks.includes('VIDEOTUOTANTO'))) { isProfiledMatch = true; } } if (isProfiledMatch) return true; const companyContent = ((c.tags || '') + ' ' + (c.kategoria || '') + ' ' + (c.nimi || '') + ' ' + (c.profiling?.core?.sub_contexts?.join(' ') || '') + ' ' + (c.profiling?.core?.node_links?.join(' ') || '')).toLowerCase(); return opt.tags.some(tag => companyContent.includes(tag.toLowerCase())); }); console.log(matches.map(c => c.nimi));
